# E2-Skeptic three-route assess for S47-T1-A-E2
def assess(record: dict) -> str:
    required = {'metric', 'seed', 'rerun_metric', 'params', 'tolerance', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])
    except Exception:
        return 'MARK_RUN_NONREPRODUCIBLE'
    return 'PASS' if ok else 'MARK_RUN_NONREPRODUCIBLE'

record = {"case_id": "CASO-TAC-047-1A", **{"seed":42,"params":{"depth":4},"metric":0.81,"rerun_metric":0.805,"tolerance":0.01}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'tolerance'}
print(assess(valid), assess(invalid), assess(incomplete))

